barrio banda Cajero {
    cabal saldo = 500;

    barrio nimais retirarPisto(cabal cantidad) {
        simon (cantidad > saldo) {
            morongazo estrenar GranClavo("No tenes tanto pisto chavo");
        }
        saldo = saldo - cantidad;
        chotear("Retiro exitoso. Te queda: " + saldo);
    }
}

barrio banda Manejador {

    barrio nimais procesarDato(cabal numero) {
        calale {
            simon (numero == 0) {
                morongazo estrenar GranClavo("¡No seas así, vos! No se puede dividir por cero.");
            }

            cabal resultado = 100 / numero;
            chotear("El resultado es: " + resultado);

        } atrapalo (GranClavo e) {
            chotear("¡Se armó un GranClavo!: " + e.quepaso());
        }
    }
}

